// =====================================================
// N5 Müügiandmete agregaator
// Sisend: Google Sheets Read SisendLogi (25 rida)
// Väljund: kõik, mida AI vajab + raporti meta
// =====================================================

const rows = $input.all().map(item => item.json);

if (!rows.length) {
  throw new Error('SisendLogi tühi — kontrolli Google Sheets Read node');
}

const num = (v) => Number(v) || 0;
const sum = (key) => rows.reduce((s, r) => s + num(r[key]), 0);
const sumWhere = (filter, key) => rows.filter(filter).reduce((s, r) => s + num(r[key]), 0);

const totalRevenue = sum('revenue_eur');
const totalOrders = sum('orders');
const days = new Set(rows.map(r => r.date)).size;
const avgDailyRevenue = Math.round(totalRevenue / days);
const avgOrderValue = Number((totalRevenue / totalOrders).toFixed(2));

const stores = ['Tallinn', 'Tartu', 'Pärnu', 'Narva', 'Online'];
const storeStats = stores.map(store => {
  const revenue = sumWhere(r => r.store === store, 'revenue_eur');
  return {
    store,
    revenue,
    orders: sumWhere(r => r.store === store, 'orders'),
    share_pct: Number(((revenue / totalRevenue) * 100).toFixed(2))
  };
});

const highRiskRows = rows.filter(r => r.stock_risk === 'high');
const highRiskStores = [...new Set(highRiskRows.map(r => r.store))];
const highRiskCategories = [...new Set(highRiskRows.map(r => r.category))];
const highRiskNotes = highRiskRows.map(r => `${r.date} ${r.store}: ${r.note}`);

const narvaShare = storeStats.find(s => s.store === 'Narva').share_pct;
const NARVA_TARGET = 12;

const dates = [...new Set(rows.map(r => r.date))].sort();
const period = `${dates[0]} kuni ${dates[dates.length - 1]} (${days} päeva, ${rows.length} rida)`;

return [{
  json: {
    period,
    totals: {
      revenue: totalRevenue,
      orders: totalOrders,
      avgDailyRevenue,
      avgOrderValue,
      kpiDailyRevenue: 3500,
      kpiAchievement_pct: Number(((avgDailyRevenue / 3500) * 100).toFixed(1))
    },
    storeStats,
    narva: {
      share_pct: narvaShare,
      target_pct: NARVA_TARGET,
      gap_pp: Number((NARVA_TARGET - narvaShare).toFixed(2)),
      status: narvaShare < 8 ? 'CRITICAL' : narvaShare < NARVA_TARGET ? 'BELOW_TARGET' : 'OK'
    },
    stockRisk: {
      highCount: highRiskRows.length,
      kpiMaxHighPerWeek: 3,
      stores: highRiskStores,
      categories: highRiskCategories,
      notes: highRiskNotes,
      status: highRiskRows.length > 3 ? 'EXCEEDS_KPI' : 'WITHIN_KPI'
    },
    rawData: rows
  }
}];
